/**
 * Emits index.ts — barrel re-exports.
 * Consumes NodeMap directly. Static output — doesn't depend on node list.
 */

import type { NodeMap } from '../compiler/types.ts';

export interface EmitIndexConfig {
	grammar: string;
	nodeMap: NodeMap;
}

export function emitIndex(_config: EmitIndexConfig): string {
	return [
		'// Auto-generated by @sittir/codegen — do not edit',
		'',
		'// Types (grammar + construction types + navigation types + enums)',
		"export * from './types.js';",
		'',
		'// Factories (ir namespace with .from(), plus tree-shakeable supertype groups)',
		"export * from './ir.js';",
		'',
		'// Shared resolution utilities',
		"export * from './utils.js';",
		'',
		'// Tree node hydration',
		"export { readTreeNode, wrapNode } from './wrap.js';",
		'',
		'// .from() resolution (tree-shakeable, separate from factories)',
		"export * from './from.js';",
		'',
		'// Constants (node kinds, keywords, operators)',
		"export * from './consts.js';",
		'',
		'// Type guards (is × shape composition, assert + throw)',
		"export { is, isTree, isNode, assert } from './is.js';",
		"export type { IsGuards, AssertGuards } from './is.js';",
		'',
		'// Core re-exports',
		"export { createRenderer } from '@sittir/core';",
		"export type { NodeData, TreeNode } from './types.js';",
		"export type { Edit, CSTNode, RenderContext } from '@sittir/types';",
		'',
		'// Spec 012 boundary shim — backend-dispatching render/toEdit/',
		'// applyEdits. Routes through `getActiveBackend()` so consumers',
		'// (codemods, scripts) get native automatically when the napi',
		'// `.node` is loadable, TS otherwise. The raw `createRenderer`',
		'// re-export above stays for callers that want the TS engine',
		'// explicitly without going through the selector.',
		"export { render, toEdit, applyEdits } from './boundary.js';",
		'',
		'// Backend selection (spec 012) — native vs. typescript fallback shim.',
		"export { getActiveBackend } from './backend.js';",
		"export type { BackendName, BackendStatus } from './backend.js';",
		''
	].join('\n');
}
